+    #[test]
+    fn events_after_quit_ignored() {
+        let mut runner = WasmRunner::new(Counter { value: 0 }, 80, 24);
+        runner.init();
+
+        runner.step_event(key_event('q'));
+        assert!(!runner.is_running());
+
+        let r = runner.step_event(key_event('+'));
+        assert_eq!(r.events_processed, 0);
