+    #[test]
+    fn step_before_init_is_noop() {
+        let mut runner = WasmRunner::new(Counter { value: 0 }, 80, 24);
+        let r = runner.step(Duration::ZERO);
+        assert_eq!(r.events_processed, 0);
+        assert!(!runner.is_initialized());
+    }
